        let entry = "[\(timestamp)] [\(level.label)] \(message)\n"
        append(entry)
    }

    // MARK: - Private

    private func append(_ entry: String) {
        guard let data = entry.data(using: .utf8) else { return }

        if !FileManager.default.fileExists(atPath: filePath) {
